const m = require('./core/zakFinalAuthorityContract');
const required = [
  'ZAK_FINAL_AUTHORITY_CONTRACT_STATUSES',
  'ZAK_FINAL_AUTHORITY_CONTRACT_REQUIRED_APPROVALS',
  'ZAK_FINAL_AUTHORITY_CONTRACT_NON_GRANTS',
  'createZakFinalAuthorityContract',
  'validateZakFinalAuthorityContract',
  'assertZakFinalAuthorityContract',
  'summarizeZakFinalAuthorityContract',
];
for (const key of required) {
  if (!(key in m)) throw new Error('missing export ' + key);
}
const c = m.createZakFinalAuthorityContract();
const r = m.validateZakFinalAuthorityContract(c);
if (!r.valid) throw new Error(r.errors.join('; '));
if (c.canonicalAuthorityContract !== 'ZakFinalAuthorityContract') throw new Error('wrong canonical contract');
if (c.duplicateAuthoritySourcesAllowed !== false) throw new Error('duplicate authority must be blocked');
if (c.grants.fileMoveAuthority !== false) throw new Error('file move authority must not be granted');
if (c.approvalRules.modelOutputApprovalAccepted !== false) throw new Error('model approval must be blocked');
if (c.approvalRules.generatedCodeApprovalAccepted !== false) throw new Error('generated approval must be blocked');
console.log('zak_final_authority_contract_export_probe_passed');
